is_supported_model() {
  local m="${1:-}" l
  [ -n "$m" ] || return 1
  l="$(printf '%s' "$m" | tr '[:upper:]' '[:lower:]')"
  case "$l" in
    *image*|*imagen*|*img*|*vision*|*vqa*|*vit*|*clip*|*render*|*generate-image*|*generate_image* ) return 1 ;;
    *audio*|*speech*|*tts*|*wav2vec*|*whisper*|*native-audio* ) return 1 ;;
    *embed*|*embedding*|*vector* ) return 1 ;;
    *multimodal*|*vision_audio*|*vision-audio* ) return 1 ;;
    *) return 0 ;;
  esac
}

load_local_config() {
  local cfg="${GROQBASH_CONFIG_DIR%/}/config" key val
  [ -f "$cfg" ] || return 0
  while IFS= read -r line || [ -n "$line" ]; do
    case "$line" in ''|\#*) continue ;; esac
    key="${line%%=*}"
    val="${line#*=}"
    case "$key" in
      MODEL) [ -n "$val" ] && MODEL="$val" ;;
      TEMPERATURE|TURE) [ -n "$val" ] && TURE="$val" ;;
      MAX_TOKENS) [ -n "$val" ] && MAX_TOKENS="$val" ;;
      FORMAT) [ -n "$val" ] && OUTPUT_MODE="$val" ;;
      THRESHOLD) [ -n "$val" ] && THRESHOLD="$val" ;;
    esac
  done < "$cfg"
}

load_whitelist() {
  ALLOWED_MODELS=""
  if [ -f "$MODELS_FILE" ] && [ -s "$MODELS_FILE" ]; then
    ALLOWED_MODELS="$(awk '{ gsub(/^models\//,""); sub(/^[[:space:]]+/,""); sub(/[[:space:]]+$/,""); if (NF) print }' "$MODELS_FILE" 2>/dev/null || true)"
  fi
}

is_tty_out() {
  [ -t 1 ]
}

